<?php $editing = !empty($editDeal); ?>
<div class="page-header"><div><h2>Deals</h2><p>Opportunity pipeline, ownership, projected revenue, and close timing.</p></div></div>
<div class="grid-two">
<div class="card"><h3><?= $editing ? 'Edit Deal' : 'Add Deal' ?></h3><form method="post" class="stack-form"><?= csrf_field() ?><input type="hidden" name="action" value="<?= $editing ? 'update' : 'create' ?>"><?php if ($editing): ?><input type="hidden" name="id" value="<?= e((string)$editDeal['id']) ?>"><?php endif; ?><input name="deal_name" placeholder="Deal Name" value="<?= e($editDeal['deal_name'] ?? '') ?>" required><input name="client_name" placeholder="Client Name" value="<?= e($editDeal['client_name'] ?? '') ?>" required><select name="stage"><?php foreach (['Discovery','Proposal','Negotiation','Closed Won','Closed Lost'] as $stage): ?><option value="<?= e($stage) ?>" <?= (($editDeal['stage'] ?? 'Discovery')===$stage)?'selected':''; ?>><?= e($stage) ?></option><?php endforeach; ?></select><input name="amount" placeholder="Amount" value="<?= e((string)($editDeal['amount'] ?? '')) ?>"><select name="owner_user_id"><option value="">Owner</option><?php foreach ($assignableUsers as $user): ?><option value="<?= e((string)$user['id']) ?>" <?= ((string)($editDeal['owner_user_id'] ?? '') === (string)$user['id']) ? 'selected' : '' ?>><?= e($user['full_name']) ?> · <?= e($user['role']) ?></option><?php endforeach; ?></select><input type="date" name="close_date" value="<?= e($editDeal['close_date'] ?? '') ?>"><textarea name="notes" placeholder="Notes"><?= e($editDeal['notes'] ?? '') ?></textarea><div class="actions"><button type="submit"><?= $editing ? 'Save Changes' : 'Create Deal' ?></button><?php if ($editing): ?><a class="btn-muted" href="index.php?page=deals">Cancel</a><?php endif; ?></div></form></div>
<div class="card"><h3>Deal Pipeline</h3><table><thead><tr><th>Deal</th><th>Stage</th><th>Value</th><th>Owner</th><th></th></tr></thead><tbody><?php foreach ($deals as $row): ?><tr><td><?= e($row['deal_name']) ?><div class="muted"><?= e($row['client_name']) ?></div></td><td><span class="tag"><?= e($row['stage']) ?></span></td><td><?= money($row['amount']) ?></td><td><?= e($row['owner_name']) ?></td><td class="table-actions"><a href="index.php?page=deals&id=<?= e((string)$row['id']) ?>">Edit</a><?php if (App\Core\Auth::can('deals','delete')): ?><form method="post" onsubmit="return confirm('Delete this deal?');"><?= csrf_field() ?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?= e((string)$row['id']) ?>"><button class="btn-danger" type="submit">Delete</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div>
</div>
